using namespace sqlgen::literals;

// Helper function to map table names to their corresponding types
std::map<std::string, rfl::Type> get_table_type_map() {
    return {
        {"Student", rfl::type<Student>()},
        {"Course", rfl::type<Course>()},
        {"Score", rfl::type<Score>()},
        {"Major", rfl::type<Major>()}
    };
}

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
    // Create database connection
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // Get the table type from the name
    auto table_map = get_table_type_map();
    auto table_type = table_map.find(table_name);
    if (table_type == table_map.end()) {
        throw std::invalid_argument("Invalid table name");
    }

    // Create insert operation and execute
    auto insert_op = sqlgen::insert(records);
    auto result = insert_op(conn);
    if (!result) {
        throw std::runtime_error("Failed to insert records");
    }
}

void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const std::string& new_value) {
    // Create database connection
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // Determine the table type based on table name
    if (table_name == "Student") {
        using T = Student;
        auto update_op = sqlgen::update<T>(
            T::SNo.set(new_value)  // Using SNo as primary key for Student
        );
        update_op = update_op | sqlgen::where(T::SNo == record_id);
        auto result = update_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to update Student record");
        }
    } else if (table_name == "Course") {
        using T = Course;
        auto update_op = sqlgen::update<T>(
            T::CID.set(std::stoul(new_value))  // CID is uint32_t with auto_incr
        );
        update_op = update_op | sqlgen::where(T::CID == std::stoul(record_id));
        auto result = update_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to update Course record");
        }
    } else if (table_name == "Score") {
        using T = Score;
        auto update_op = sqlgen::update<T>(
            T::ScID.set(std::stoul(new_value))  // ScID is uint32_t with auto_incr
        );
        update_op = update_op | sqlgen::where(T::ScID == std::stoul(record_id));
        auto result = update_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to update Score record");
        }
    } else if (table_name == "Major") {
        using T = Major;
        auto update_op = sqlgen::update<T>(
            T::MID.set(std::stoul(new_value))  // MID is uint32_t
        );
        update_op = update_op | sqlgen::where(T::MID == std::stoul(record_id));
        auto result = update_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to update Major record");
        }
    } else {
        throw std::invalid_argument("Invalid table name");
    }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
    // Create database connection
    auto conn_result = sqlgen::sqlite::connect(db_path);
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // Determine the table type based on table name
    if (table_name == "Student") {
        using T = Student;
        auto delete_op = sqlgen::delete_from<T> | sqlgen::where(T::SNo == record_id);
        auto result = delete_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete Student record");
        }
    } else if (table_name == "Course") {
        using T = Course;
        auto delete_op = sqlgen::delete_from<T> | sqlgen::where(T::CID == std::stoul(record_id));
        auto result = delete_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete Course record");
        }
    } else if (table_name == "Score") {
        using T = Score;
        auto delete_op = sqlgen::delete_from<T> | sqlgen::where(T::ScID == std::stoul(record_id));
        auto result = delete_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete Score record");
        }
    } else if (table_name == "Major") {
        using T = Major;
        auto delete_op = sqlgen::delete_from<T> | sqlgen::where(T::MID == std::stoul(record_id));
        auto result = delete_op(conn);
        if (!result) {
            throw std::runtime_error("Failed to delete Major record");
        }
    } else {
        throw std::invalid_argument("Invalid table name");
    }
}
