```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Begin a transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return -2; // Transaction start failed
  }

  try {
    // 3. Delete users where last_login < 2025-01-01
    auto delete_result = (delete_from<User> | where("last_login"_c < "2025-01-01"))(conn);
    if (!delete_result) {
      // Rollback on delete failure
      conn->rollback();
      return -3; // Delete operation failed
    }

    // 4. Commit the transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
      return -4; // Commit failed
    }

    // 5. Return the commit result
    return 0; // Success

  } catch (...) {
    // Rollback on exception
    conn->rollback();
    return -5; // Exception occurred
  }
}

} // namespace delete_inactive_users
```

