namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Begin transaction
  auto transaction_result = conn | sqlgen::begin_transaction;
  if (!transaction_result) {
    return false;
  }

  try {
    // 3. Read from_account balance to verify sufficient funds
    auto read_result = (sqlgen::read<std::vector<Account>> 
                        | sqlgen::where("account_id"_c == from_account_id))(conn);

    if (!read_result) {
      conn | sqlgen::rollback;
      return false;
    }

    auto accounts = read_result.value();
    if (accounts.empty() || accounts[0].balance < amount) {
      conn | sqlgen::rollback;
      return false;
    }

    // 4. Update from_account: balance = balance - amount (with condition)
    auto update_from_result = (sqlgen::update<Account>("balance"_c.set("balance"_c - amount))
                              | sqlgen::where("account_id"_c == from_account_id 
                                            && "balance"_c >= amount))(conn);

    if (!update_from_result) {
      conn | sqlgen::rollback;
      return false;
    }

    // 5. Update to_account: balance = balance + amount
    auto update_to_result = (sqlgen::update<Account>("balance"_c.set("balance"_c + amount))
                             | sqlgen::where("account_id"_c == to_account_id))(conn);

    if (!update_to_result) {
      conn | sqlgen::rollback;
      return false;
    }

    // 6. Commit transaction if all steps succeed
    auto commit_result = conn | sqlgen::commit;
    if (!commit_result) {
      conn | sqlgen::rollback;
      return false;
    }

    return true;

  } catch (...) {
    // Rollback on any exception
    conn | sqlgen::rollback;
    return false;
  }
}

}  // namespace transaction_transfer_funds
