```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = *conn_result;

  // 2. Read Sales data from the database
  auto sales_result = sqlgen::read<std::vector<Sales>>(conn);
  if (!sales_result) {
    throw std::runtime_error("Failed to read sales data");
  }
  auto sales = *sales_result;

  // 3. Create a map to accumulate weekday totals
  std::vector<WeekdayStats> weekday_totals(7); // 0=Monday to 6=Sunday

  // 4. Iterate through each sale and extract weekday
  for (const auto& sale : sales) {
    // Extract weekday from sale_time using sqlgen's date_part function
    auto weekday_result = sqlgen::internal::to_weekday(sale.sale_time);
    if (!weekday_result) {
      throw std::runtime_error("Failed to extract weekday from timestamp");
    }
    int weekday = *weekday_result;

    // 5. Aggregate totals per weekday
    weekday_totals[weekday].weekday = weekday;
    weekday_totals[weekday].total_quantity += sale.quantity;
  }

  // 6. Return the aggregated results
  return weekday_totals;
}

}  // namespace weekday_sales_analysis
```

